     9→public class PriceRepository
    10→{
    11→    // ── Materials ──
    12→    public List<Material> GetMaterials()
    13→    {
    14→        using var conn = Database.CreateConnection();
    15→        return conn.Query<Material>("SELECT * FROM Materials ORDER BY SortOrder, Id").AsList();
    16→    }
    17→
    18→    public void SaveMaterial(Material m)
    19→    {
    20→        using var conn = Database.CreateConnection();
    21→        if (m.Id == 0)
    22→            m.Id = (int)conn.ExecuteScalar<long>(
    23→                "INSERT INTO Materials(Name, Description, SortOrder) VALUES(@Name, @Description, @SortOrder); SELECT last_insert_rowid();", m);
    24→        else
    25→            conn.Execute("UPDATE Materials SET Name=@Name, Description=@Description, SortOrder=@SortOrder WHERE Id=@Id", m);
    26→    }
    27→
    28→    public void DeleteMaterial(int id)
    29→    {
    30→        using var conn = Database.CreateConnection();
    31→        conn.Execute("DELETE FROM Materials WHERE Id=@id", new { id });
    32→    }
    33→
    34→    // ── ProductTypes ──
    35→    public List<ProductType> GetProductTypes(int? materialId = null)
    36→    {
    37→        using var conn = Database.CreateConnection();
    38→        var sql = @"SELECT pt.*, m.Name AS MaterialName
    39→                    FROM ProductTypes pt JOIN Materials m ON pt.MaterialId=m.Id";
    40→        if (materialId.HasValue)
    41→            sql += " WHERE pt.MaterialId=@materialId";
    42→        sql += " ORDER BY m.SortOrder, pt.SortOrder, pt.Id";
