using Dapper;
using PanelEstimator.Models;

namespace PanelEstimator.Data;

/// <summary>
/// 단가표 CRUD 리포지토리
/// </summary>
public class PriceRepository
{
    // ── Materials ──
    public List<Material> GetMaterials()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<Material>("SELECT * FROM Materials ORDER BY SortOrder, Id").AsList();
    }

    public void SaveMaterial(Material m)
    {
        using var conn = Database.CreateConnection();
        if (m.Id == 0)
            m.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO Materials(Name, Description, SortOrder) VALUES(@Name, @Description, @SortOrder); SELECT last_insert_rowid();", m);
        else
            conn.Execute("UPDATE Materials SET Name=@Name, Description=@Description, SortOrder=@SortOrder WHERE Id=@Id", m);
    }

    public void DeleteMaterial(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM Materials WHERE Id=@id", new { id });
    }

    // ── ProductTypes ──
    public List<ProductType> GetProductTypes(int? materialId = null)
    {
        using var conn = Database.CreateConnection();
        var sql = @"SELECT pt.*, m.Name AS MaterialName
                    FROM ProductTypes pt JOIN Materials m ON pt.MaterialId=m.Id";
        if (materialId.HasValue)
            sql += " WHERE pt.MaterialId=@materialId";
        sql += " ORDER BY m.SortOrder, pt.SortOrder, pt.Id";
        return conn.Query<ProductType>(sql, new { materialId }).AsList();
    }

    public void SaveProductType(ProductType pt)
    {
        using var conn = Database.CreateConnection();
        if (pt.Id == 0)
            pt.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO ProductTypes(MaterialId, Name, SortOrder) VALUES(@MaterialId, @Name, @SortOrder); SELECT last_insert_rowid();", pt);
        else
            conn.Execute("UPDATE ProductTypes SET MaterialId=@MaterialId, Name=@Name, SortOrder=@SortOrder WHERE Id=@Id", pt);
    }

    public void DeleteProductType(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM ProductTypes WHERE Id=@id", new { id });
    }

    // ── Grades ──
    public List<Grade> GetGrades(int? materialId = null)
    {
        using var conn = Database.CreateConnection();
        var sql = @"SELECT g.*, m.Name AS MaterialName
                    FROM Grades g JOIN Materials m ON g.MaterialId=m.Id";
        if (materialId.HasValue)
            sql += " WHERE g.MaterialId=@materialId";
        sql += " ORDER BY m.SortOrder, g.SortOrder, g.Id";
        return conn.Query<Grade>(sql, new { materialId }).AsList();
    }

    public void SaveGrade(Grade g)
    {
        using var conn = Database.CreateConnection();
        if (g.Id == 0)
            g.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO Grades(MaterialId, Name, SortOrder) VALUES(@MaterialId, @Name, @SortOrder); SELECT last_insert_rowid();", g);
        else
            conn.Execute("UPDATE Grades SET MaterialId=@MaterialId, Name=@Name, SortOrder=@SortOrder WHERE Id=@Id", g);
    }

    public void DeleteGrade(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM Grades WHERE Id=@id", new { id });
    }

    // ── PanelPrices ──
    public List<PanelPrice> GetPanelPrices(int? productTypeId = null, int? gradeId = null)
    {
        using var conn = Database.CreateConnection();
        var sql = @"SELECT pp.*, pt.Name AS ProductTypeName, g.Name AS GradeName, m.Name AS MaterialName
                    FROM PanelPrices pp
                    JOIN ProductTypes pt ON pp.ProductTypeId=pt.Id
                    JOIN Grades g ON pp.GradeId=g.Id
                    JOIN Materials m ON pt.MaterialId=m.Id
                    WHERE 1=1";
        if (productTypeId.HasValue) sql += " AND pp.ProductTypeId=@productTypeId";
        if (gradeId.HasValue) sql += " AND pp.GradeId=@gradeId";
        sql += " ORDER BY m.SortOrder, pt.SortOrder, pp.ThicknessMm, g.SortOrder";
        return conn.Query<PanelPrice>(sql, new { productTypeId, gradeId }).AsList();
    }

    public void SavePanelPrice(PanelPrice pp)
    {
        using var conn = Database.CreateConnection();
        if (pp.Id == 0)
            pp.Id = (int)conn.ExecuteScalar<long>(
                @"INSERT INTO PanelPrices(ProductTypeId, GradeId, ThicknessMm, UnitPrice, FireRatingMin, Notes)
                  VALUES(@ProductTypeId, @GradeId, @ThicknessMm, @UnitPrice, @FireRatingMin, @Notes);
                  SELECT last_insert_rowid();", pp);
        else
            conn.Execute(
                @"UPDATE PanelPrices SET ProductTypeId=@ProductTypeId, GradeId=@GradeId,
                  ThicknessMm=@ThicknessMm, UnitPrice=@UnitPrice, FireRatingMin=@FireRatingMin, Notes=@Notes
                  WHERE Id=@Id", pp);
    }

    public void DeletePanelPrice(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM PanelPrices WHERE Id=@id", new { id });
    }

    // ── ColorSurcharges ──
    public List<ColorSurcharge> GetColorSurcharges()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<ColorSurcharge>(
            @"SELECT cs.*, m.Name AS MaterialName
              FROM ColorSurcharges cs LEFT JOIN Materials m ON cs.MaterialId=m.Id
              ORDER BY cs.Id").AsList();
    }

    public void SaveColorSurcharge(ColorSurcharge cs)
    {
        using var conn = Database.CreateConnection();
        if (cs.Id == 0)
            cs.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO ColorSurcharges(MaterialId, ColorName, SurchargePerSide, Notes) VALUES(@MaterialId, @ColorName, @SurchargePerSide, @Notes); SELECT last_insert_rowid();", cs);
        else
            conn.Execute("UPDATE ColorSurcharges SET MaterialId=@MaterialId, ColorName=@ColorName, SurchargePerSide=@SurchargePerSide, Notes=@Notes WHERE Id=@Id", cs);
    }

    public void DeleteColorSurcharge(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM ColorSurcharges WHERE Id=@id", new { id });
    }

    // ── OptionSurcharges ──
    public List<OptionSurcharge> GetOptionSurcharges()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<OptionSurcharge>(
            @"SELECT os.*, m.Name AS MaterialName
              FROM OptionSurcharges os LEFT JOIN Materials m ON os.MaterialId=m.Id
              ORDER BY os.Id").AsList();
    }

    public void SaveOptionSurcharge(OptionSurcharge os)
    {
        using var conn = Database.CreateConnection();
        if (os.Id == 0)
            os.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO OptionSurcharges(MaterialId, OptionName, SurchargeAmount, Notes) VALUES(@MaterialId, @OptionName, @SurchargeAmount, @Notes); SELECT last_insert_rowid();", os);
        else
            conn.Execute("UPDATE OptionSurcharges SET MaterialId=@MaterialId, OptionName=@OptionName, SurchargeAmount=@SurchargeAmount, Notes=@Notes WHERE Id=@Id", os);
    }

    public void DeleteOptionSurcharge(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM OptionSurcharges WHERE Id=@id", new { id });
    }

    // ── ColorSteelProducts ──
    public List<ColorSteelProduct> GetColorSteelProducts()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<ColorSteelProduct>("SELECT * FROM ColorSteelProducts ORDER BY Id").AsList();
    }

    public void SaveColorSteelProduct(ColorSteelProduct p)
    {
        using var conn = Database.CreateConnection();
        if (p.Id == 0)
            p.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO ColorSteelProducts(Name, ThicknessMm, UnitPrice, Notes) VALUES(@Name, @ThicknessMm, @UnitPrice, @Notes); SELECT last_insert_rowid();", p);
        else
            conn.Execute("UPDATE ColorSteelProducts SET Name=@Name, ThicknessMm=@ThicknessMm, UnitPrice=@UnitPrice, Notes=@Notes WHERE Id=@Id", p);
    }

    public void DeleteColorSteelProduct(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM ColorSteelProducts WHERE Id=@id", new { id });
    }

    // ── SkylightProducts ──
    public List<SkylightProduct> GetSkylightProducts()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<SkylightProduct>("SELECT * FROM SkylightProducts ORDER BY ThicknessMm").AsList();
    }

    public void SaveSkylightProduct(SkylightProduct p)
    {
        using var conn = Database.CreateConnection();
        if (p.Id == 0)
            p.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO SkylightProducts(Name, ThicknessMm, UnitPrice, Notes) VALUES(@Name, @ThicknessMm, @UnitPrice, @Notes); SELECT last_insert_rowid();", p);
        else
            conn.Execute("UPDATE SkylightProducts SET Name=@Name, ThicknessMm=@ThicknessMm, UnitPrice=@UnitPrice, Notes=@Notes WHERE Id=@Id", p);
    }

    public void DeleteSkylightProduct(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM SkylightProducts WHERE Id=@id", new { id });
    }

    // ── Accessories ──
    public List<Accessory> GetAccessories()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<Accessory>("SELECT * FROM Accessories ORDER BY Category, Id").AsList();
    }

    public void SaveAccessory(Accessory a)
    {
        using var conn = Database.CreateConnection();
        if (a.Id == 0)
            a.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO Accessories(Category, Name, Specification, Unit, UnitPrice, Notes) VALUES(@Category, @Name, @Specification, @Unit, @UnitPrice, @Notes); SELECT last_insert_rowid();", a);
        else
            conn.Execute("UPDATE Accessories SET Category=@Category, Name=@Name, Specification=@Specification, Unit=@Unit, UnitPrice=@UnitPrice, Notes=@Notes WHERE Id=@Id", a);
    }

    public void DeleteAccessory(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM Accessories WHERE Id=@id", new { id });
    }

    // ── SashProducts ──
    public List<SashProduct> GetSashProducts()
    {
        using var conn = Database.CreateConnection();
        return conn.Query<SashProduct>("SELECT * FROM SashProducts ORDER BY Type, Width, Height").AsList();
    }

    public void SaveSashProduct(SashProduct s)
    {
        using var conn = Database.CreateConnection();
        if (s.Id == 0)
            s.Id = (int)conn.ExecuteScalar<long>(
                "INSERT INTO SashProducts(Type, Width, Height, PanelThicknessMm, UnitPrice, Notes) VALUES(@Type, @Width, @Height, @PanelThicknessMm, @UnitPrice, @Notes); SELECT last_insert_rowid();", s);
        else
            conn.Execute("UPDATE SashProducts SET Type=@Type, Width=@Width, Height=@Height, PanelThicknessMm=@PanelThicknessMm, UnitPrice=@UnitPrice, Notes=@Notes WHERE Id=@Id", s);
    }

    public void DeleteSashProduct(int id)
    {
        using var conn = Database.CreateConnection();
        conn.Execute("DELETE FROM SashProducts WHERE Id=@id", new { id });
    }
}

