using Microsoft.Data.Sqlite;
using Dapper;

namespace PanelEstimator.Data;

public static class Database
{
    private static string _dbPath = null!;
    private static string _connectionString = null!;

    public static string DbPath => _dbPath;

    public static void Initialize(string dbPath)
    {
        _dbPath = dbPath;
        _connectionString = $"Data Source={_dbPath}";

        using var conn = CreateConnection();
        conn.Open();  // ← 버그: CreateConnection() 내부에서 이미 Open() 호출함 → InvalidOperationException 발생

        // WAL 모드 + FK 활성화
        conn.Execute("PRAGMA journal_mode=WAL;");
        conn.Execute("PRAGMA foreign_keys=ON;");

        // 스키마 생성
        var schemaPath = Path.Combine(AppContext.BaseDirectory, "Data", "DbSchema.sql");
        if (File.Exists(schemaPath))
        {
            var sql = File.ReadAllText(schemaPath);
            conn.Execute(sql);
        }
        else
        {
            CreateSchema(conn);
        }
    }

    public static SqliteConnection CreateConnection()
    {
        var conn = new SqliteConnection(_connectionString);
        conn.Open();
        conn.Execute("PRAGMA foreign_keys=ON;");
        return conn;
    }
}

