CREATE TABLE IF NOT EXISTS Materials (Id INTEGER PRIMARY KEY AUTOINCREMENT, Name TEXT NOT NULL UNIQUE, Description TEXT, SortOrder INTEGER DEFAULT 0);
CREATE TABLE IF NOT EXISTS ProductTypes (Id INTEGER PRIMARY KEY AUTOINCREMENT, MaterialId INTEGER NOT NULL REFERENCES Materials(Id), Name TEXT NOT NULL, SortOrder INTEGER DEFAULT 0, UNIQUE(MaterialId, Name));
CREATE TABLE IF NOT EXISTS Grades (Id INTEGER PRIMARY KEY AUTOINCREMENT, MaterialId INTEGER NOT NULL REFERENCES Materials(Id), Name TEXT NOT NULL, SortOrder INTEGER DEFAULT 0, UNIQUE(MaterialId, Name));
CREATE TABLE IF NOT EXISTS PanelPrices (Id INTEGER PRIMARY KEY AUTOINCREMENT, ProductTypeId INTEGER NOT NULL REFERENCES ProductTypes(Id), GradeId INTEGER NOT NULL REFERENCES Grades(Id), ThicknessMm INTEGER NOT NULL, UnitPrice INTEGER NOT NULL, FireRatingMin INTEGER, Notes TEXT, UNIQUE(ProductTypeId, GradeId, ThicknessMm));
CREATE TABLE IF NOT EXISTS ColorSurcharges (Id INTEGER PRIMARY KEY AUTOINCREMENT, MaterialId INTEGER REFERENCES Materials(Id), ColorName TEXT NOT NULL, SurchargePerSide INTEGER NOT NULL, Notes TEXT);
CREATE TABLE IF NOT EXISTS OptionSurcharges (Id INTEGER PRIMARY KEY AUTOINCREMENT, MaterialId INTEGER REFERENCES Materials(Id), OptionName TEXT NOT NULL, SurchargeAmount INTEGER NOT NULL, Notes TEXT);
CREATE TABLE IF NOT EXISTS ColorSteelProducts (Id INTEGER PRIMARY KEY AUTOINCREMENT, Name TEXT NOT NULL, ThicknessMm REAL NOT NULL, UnitPrice INTEGER, Notes TEXT);
CREATE TABLE IF NOT EXISTS SkylightProducts (Id INTEGER PRIMARY KEY AUTOINCREMENT, Name TEXT NOT NULL DEFAULT 'PC채광판 V-250', ThicknessMm REAL NOT NULL, UnitPrice INTEGER NOT NULL, Notes TEXT);
CREATE TABLE IF NOT EXISTS Accessories (Id INTEGER PRIMARY KEY AUTOINCREMENT, Category TEXT NOT NULL, Name TEXT NOT NULL, Specification TEXT, Unit TEXT DEFAULT 'm', UnitPrice INTEGER, Notes TEXT);
CREATE TABLE IF NOT EXISTS SashProducts (Id INTEGER PRIMARY KEY AUTOINCREMENT, Type TEXT NOT NULL, Width INTEGER NOT NULL, Height INTEGER NOT NULL, PanelThicknessMm INTEGER, UnitPrice INTEGER NOT NULL, Notes TEXT);
CREATE INDEX IF NOT EXISTS IX_PanelPrices_Lookup ON PanelPrices(ProductTypeId, ThicknessMm, GradeId);

